import { expect, test, describe } from "vitest";
import { BettiSignatureSieve } from "../betti-signature-sieve";

describe("Betti-Number Signature Sieve — Topological Patching", () => {
  test("patchStream identifies and fills a Betti-1 hole", () => {
    const stream = new Float32Array([0.1, 0.1, 0.9, 0.1, 0.1]); // A clear glitch at index 2
    const patched = BettiSignatureSieve.patchStream(stream);
    
    expect(patched[2]).toBeLessThan(0.9);
    expect(patched[2]).toBeCloseTo(0.1); // Patched to neighbor average
  });

  test("sieveVideoFrames maintains continuity across frames", () => {
    const f1 = new Float32Array([0.5, 0.5]);
    const f2 = new Float32Array([0.9, 0.5]); // Glitch in f2 at pixel 0
    const f3 = new Float32Array([0.5, 0.5]);
    
    const sieved = BettiSignatureSieve.sieveVideoFrames([f1, f2, f3]);
    
    expect(sieved[1][0]).toBeCloseTo(0.5);
    expect(sieved[1][1]).toBe(0.5); // Unchanged
  });
});
